var e=[{id:`L4_1`,type:`dialog`,speaker:`LEADER_FLORA_WEDDING_NULL`,text:{KOREA:`당신이었군요.`,JPN:`あなただったんですね。`,ENG:`It’s you.`,TWN:`原來是你。`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`LEADER_FLORA_WEDDING_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`LEADER_FLORA_WEDDING_NULL`,text:{KOREA:`어떻게 침식체를 조종하는지 모르겠지만, 이제 그만두시죠.`,JPN:`どうやって侵食体を操っているのかわかりませんが、もう諦めてください。`,ENG:`I don’t know how you’re controlling the C.O.s, but you should stop now.`,TWN:`雖然不清楚你是怎麼控制侵蝕體的，但請你收手吧。`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`LEADER_FLORA_WEDDING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`LEADER_FLORA_WEDDING_NULL`,text:{KOREA:`이 이상, 주인님의 휴가를 방해하게 두지는 않겠습니다. `,JPN:`これ以上、ご主人様の休みを邪魔するのは見過ごせません。`,ENG:`I won’t let you ruin my Master’s vacation.`,TWN:`我不允許你再打擾主人的假期。`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`LEADER_FLORA_WEDDING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`LONELY_NPC_NULL_NULL`,text:{KOREA:`크윽……!!`,JPN:`くうっ……！！`,ENG:`Hngh!!`,TWN:`唔……！！`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`LONELY_NPC_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`LONELY_NPC_NULL_NULL`,text:{KOREA:`마, 말도 안 돼……!`,JPN:`う、うそでしょ……！！`,ENG:`Th-that's impossible!`,TWN:`這…這怎麼可能……！`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`LONELY_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`LONELY_NPC_NULL_NULL`,text:{KOREA:`어떻게 카운터도 아닌 일반인이 혼자 침식체들을 제압하는 거야?`,JPN:`どうしてカウンターでもない一般人が、一人で侵食体を制圧できるの？`,ENG:`You’re not a Counter. How are you fighting all these C.O.s?`,TWN:`一個普通人怎麼可能獨自打倒侵蝕體？`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`LONELY_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`LONELY_NPC_NULL_NULL`,text:{KOREA:`게다가 그런 파렴치한 복장으로……!`,JPN:`しかもそんな恥知らずな服装で……！`,ENG:`You’re even wearing that shameless outfit!`,TWN:`而且還穿著那麼不要臉的衣服……！`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`LONELY_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`LEADER_FLORA_WEDDING_NULL`,text:{KOREA:`이 옷은 주인님이 선물해 주신 소중한 드레스입니다.`,JPN:`この服はご主人様がプレゼントしてくださった大切なドレスです。`,ENG:`This is a precious gift from my Master.`,TWN:`這件珍貴的洋裝是主人送給我的禮物。`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`LEADER_FLORA_WEDDING_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`LEADER_FLORA_WEDDING_NULL`,text:{KOREA:`그 이상의 무례한 언동은 삼가시길.`,JPN:`それ以上の無礼な言動はご遠慮ください。`,ENG:`Please stop insulting it.`,TWN:`說話請放尊重一點。`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`LEADER_FLORA_WEDDING_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`LONELY_NPC_NULL_NULL`,text:{KOREA:`주인님? 소중한 드레스……?`,JPN:`ご主人様？　大切なドレス……？`,ENG:`Your Master? A precious gift?`,TWN:`主人？珍貴的裙子……`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`LONELY_NPC_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`LONELY_NPC_NULL_NULL`,text:{KOREA:`그 말은…… 역시 당신이 선배님의 애인이란 거군요?`,JPN:`ということは……やっぱりあなたが先輩の恋人ってことですね？`,ENG:`So you really are his lover... aren’t you?`,TWN:`意思是……你果然是前輩的情人囉？`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`LONELY_NPC_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`LEADER_FLORA_WEDDING_NULL`,text:{KOREA:`……네?`,JPN:`……はい？`,ENG:`... I beg your pardon?`,TWN:`……嗯？`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`LEADER_FLORA_WEDDING_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`LONELY_NPC_NULL_NULL`,text:{KOREA:`시치미 뗄 생각 하지 마!!`,JPN:`とぼけるな！`,ENG:`Stop playing the fool!`,TWN:`少給我裝蒜！`},stage:{bg:`VILLAGE2`,slots:{L:null,C:{char_id:`LONELY_NPC_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`LONELY_NPC_NULL_NULL`,text:{KOREA:`늘 이런 식이야.`,JPN:`いつもこうだ。`,ENG:`It’s been always like this.`,TWN:`每次都這樣！`},stage:{bg:`SUMMER_BEACH`,slots:{L:{char_id:`MACHINEGAP_COFFIN_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`LEADER_FLORA_WEDDING_NULL`,face:`UNIT_LAUGH`}}}},{id:`L24_1`,type:`dialog`,speaker:`LONELY_NPC_NULL_NULL`,text:{KOREA:`내가 좋아하는 사람은 나를 좋아하지 않았어.`,JPN:`私が好きな人は私のこと好きじゃないんだ。`,ENG:`When I love someone, they never love me back.`,TWN:`我喜歡的人不喜歡我！`},stage:{bg:`SUMMER_BEACH`,slots:{L:{char_id:`MACHINEGAP_COFFIN_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`LEADER_FLORA_WEDDING_NULL`,face:`UNIT_LAUGH`}}}},{id:`L25_1`,type:`dialog`,speaker:`LONELY_NPC_NULL_NULL`,text:{KOREA:`그래서 달라지려고 노력도 해 봤지만, 결국 쓸데없는 짓이었다고.`,JPN:`それで変わろうと努力もしてみたけど、結局無駄なことだった。`,ENG:`I tried to change, but it never worked.`,TWN:`就算我很努力改變，到頭來還是白忙一場！`},stage:{bg:`SUMMER_BEACH`,slots:{L:{char_id:`MACHINEGAP_COFFIN_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`LEADER_FLORA_WEDDING_NULL`,face:`UNIT_LAUGH`}}}}];export{e as default};